# The addresses 0x2f4b20 and 0x2f4c84 fall in .data.rel.ro, not .text.
# They might be indirect function calls or thunks. Let's check dynamic symbols.
aarch64-linux-gnu-readelf -s /tmp/libmonosgen-2.0.so.sym | awk '$2 ~ /^[0-9a-f]+$/ && strtonum("0x"$2) > 0 { addr=strtonum("0x"$2); sz=strtonum("0x"$3) > 0 ? strtonum("0x"$3) : strtonum($3); for (a=0x2f4b20; a<=0x2f4c84; a+=(0x2f4c84-0x2f4b20)) { if (addr <= a && a < addr+sz) print "0x"sprintf("%x",a), "->", $0 } }' | head -10

# Also, let's try with just the function symbols from the full symtab
aarch64-linux-gnu-nm -n -C /tmp/libmonosgen-2.0.so.sym | awk '{
  addr=strtonum("0x"$1)
  if (addr <= 0x2f4b20) { prev1=$0; pa1=addr }
  if (addr <= 0x2f4c84) { prev2=$0; pa2=addr }
}
END {
  printf "0x2f4b20 (offset +0x%x): %s\n", 0x2f4b20-pa1, prev1
  printf "0x2f4c84 (offset +0x%x): %s\n", 0x2f4c84-pa2, prev2
}'

