{"command": "# Get more detailed info: function name + offset for each address
# Using addr2line with -i (inline) for better results
aarch64-linux-gnu-addr2line -f -C -i -e /tmp/libmonosgen-2.0.so.sym \
  0x222098 0x2241ac 0x1abc80 0x16de04 0x2c1a40 2>&1

echo "=== nm-based lookup for all addresses ==="
for addr in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2c1a40; do
  aarch64-linux-gnu-nm -n -C /tmp/libmonosgen-2.0.so.sym | awk -v target="$addr" '
    BEGIN { t=strtonum(target) }
    $2 ~ /[tTwW]/ { addr=strtonum("0x"$1); if (addr <= t) { prev_addr=addr; prev_sym=$3 } }
    END { printf "%s -> %s+0x%x\n", target, prev_sym, t-prev_addr }
  '
done", "description": "Get detailed symbolication with inlines", "initial_wait": 15}
